<?php
namespace Tests\Feature;use App\Models\Character;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class WalletCommandsTest extends TestCase{use RefreshDatabase;public function test_credit_and_debit_commands(){$c=Character::factory()->for(User::factory())->create();$this->artisan('game:wallet:credit',['characterId'=>$c->id,'amount'=>100])->assertExitCode(0);$this->artisan('game:wallet:debit',['characterId'=>$c->id,'amount'=>40])->assertExitCode(0);$this->assertDatabaseHas('character_wallets',['character_id'=>$c->id,'gold_balance'=>60]);}public function test_commands_reject_invalid_inputs(){$this->artisan('game:wallet:credit',['characterId'=>999999,'amount'=>1])->assertExitCode(1);$c=Character::factory()->for(User::factory())->create();$this->artisan('game:wallet:debit',['characterId'=>$c->id,'amount'=>1])->assertExitCode(1);$this->artisan('game:wallet:credit',['characterId'=>$c->id,'amount'=>0])->assertExitCode(1);$this->artisan('game:wallet:credit',['characterId'=>$c->id,'amount'=>1,'--reason'=>'hunting_reward'])->assertExitCode(1);}}
